/// <summary>
/// Abhinav 25-05-2026 BIN Qty Status activation
/// </summary>
/// <returns></returns>
public int active()
{

    int ret = next active();

    FormPartControl formpartcontrol = element.design(0).controlName("ETGBinQtyAvailable");
    formpartcontrol.visible(ETGCanadaParameters::find().EnableBinQtyStatus);

    if(ETGCanadaParameters::find().EnableBinQtyStatus)
    {
        InventDim inventdim = this.cursor();
        ETGBinQtyVisualChartHelperClass::populateBinQtyChartData(inventdim,formpartcontrol);
    }

    return ret;
}
